#!/bin/bash
# Скрипт для добавления всех секретов APatch в GitHub репозиторий

echo "🔑 Добавление секретов APatch в GitHub репозиторий..."

# Основные ключи подписи
gh secret set SIGNING_KEY --body ""

gh secret set ALIAS --body "apatch"

gh secret set KEY_STORE_PASSWORD --body "apatch123"

gh secret set KEY_PASSWORD --body "apatch123"

# Подписи APatch
gh secret set APATCH_ORIGINAL_SIGNATURE --body "1x2twMoHvfWUODv7KkRRNKBzOfEqJwRKGzJpgaz18xk="

gh secret set APATCH_REAL_SIGNATURE --body "sypblYtJUCDSbk/u67zSBUyhRj+t7n6Tm6EPuEUnku4="

# Дополнительная информация
gh secret set APATCH_PACKAGE_NAME --body "me.bmax.apatch"

gh secret set APATCH_APP_CLASS --body "APApplication"

echo "✅ Все секреты добавлены!"
echo ""
echo "📋 Добавленные секреты:"
echo "- SIGNING_KEY (ваш ключ подписи)"
echo "- ALIAS (apatch)"
echo "- KEY_STORE_PASSWORD (apatch123)"
echo "- KEY_PASSWORD (apatch123)"
echo "- APATCH_ORIGINAL_SIGNATURE (подпись из кода)"
echo "- APATCH_REAL_SIGNATURE (подпись из реального APK)"
echo "- APATCH_PACKAGE_NAME (me.bmax.apatch)"
echo "- APATCH_APP_CLASS (APApplication)"
echo ""
echo "🚀 Теперь можете запускать GitHub Actions workflows!"